import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"律师徽章","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/律师徽章.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/律师徽章.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/律师徽章.md"};function l(_,a,i,p,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"律师徽章",tabindex:"-1"},[s("律师徽章 "),e("a",{class:"header-anchor",href:"#律师徽章","aria-label":'Permalink to "律师徽章"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),o('<h1 id="律师徽章-1" tabindex="-1">律师徽章 <a class="header-anchor" href="#律师徽章-1" aria-label="Permalink to &quot;律师徽章&quot;">​</a></h1><p>律师徽章<br> 类型：奇物（饰品）<br> 价格：D+500<br> 本质：特异<br> 描述：出自《逆转裁判》系列的道具，律师徽章又名“天秤葵花章”。在最初的系列中只有一句话“没有这个徽章的话没有人会承认我的律师身份”，但剧情中也被人冒充过，属于自己打自己脸。徽章本质是律师协会颁发的证明，证明此人是一位合格律师，而徽章上的天秤代表了期望律师职责能为不能对“裁决”以外之事做出决定的法官对事情进行反面论证找出【真相】的期望。<br> 效果：佩戴本徽章进入影片时，会获得合法合规的能被查到过往经历的律师身份并附带记忆，不附带人际关系，但此时你只是一位名不见经传的律师，这是一个D级信息来源的背景身份特性。同时佩戴着这个徽章时你能感受到律师真正的武器——语言，每影片结束时，若你在影片内声明自己的律师身份且因为他人辩护而获得了声望，那么你在佩戴这一徽章时会永久获得2点社交检定上的表现加值。<br> 当你因为他人辩护而获得了至少100点正面声望或是负面声望，此徽章所带来的背景身份等级提升至C级，此时你进入影片后将会拥有一个独立的个人律师事务所，可能会拥有代步车。<br> 特殊的，若你在辩论时出示了这一道具作为证据，这一物品的表现加值将不再生效。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
